<template>
    <div>

        <div class="position-relative">
            <!-- shape Hero -->
            <section class="section-shaped my-0">
				<div class="shape shape-style-1 shape-primary image-header" style="background-image: url('img/theme/multinivel.png'); background-repeat: no-repeat; background-position: center top; background-size: cover;">
				</div>
                <div class="container shape-container d-flex">
					<div class="col px-0 mb-4">
						<div class="row py-5">
							
						</div>
					</div>
				</div>
            </section>
            <!-- 1st Hero Variation -->
        </div>
        <section class="section section-lg pt-lg-0">
            <div class="container">
                <div class="row justify-content-center mt--100">
                    <div class="col-lg-8">
                        <card shadow body-classes="p-lg-5">
							<h4>Contacto</h4>
                            <p class="mt-0">Para más información por favor llenar el siguiente formulario.</p>
							<form class="vue-form" @submit.prevent="submit">
								<input id="nombre" type="text" name="nombre" class="form-control form-control-alternative mb-3" placeholder="Nombre completo *" v-model="nombre" required>
								<input id="correo" type="email" name="correo" class="form-control form-control-alternative mb-3" placeholder="Correo electronico *" v-model="correo" required>
								<input id="telefono" type="text" name="telefono"  class="form-control form-control-alternative mb-3" placeholder="Telefono/Celular *" v-model="telefono" required>
								<textarea id="mensaje" name="mensaje" class="form-control form-control-alternative mb-4" placeholder="Mensaje *" v-model="mensaje.text" 
								:maxlength="mensaje.maxlength" rows="4" cols="80" required></textarea>
								
								<button type="submit" class="btn btn-warning float-right">
									Enviar
								</button>
								
							</form>
                        </card>
                    </div>
                </div>
            </div>
        </section>
    </div>
</template>

<script>
export default {
  name: "contacto",
  components: {},
  data: function() {
    return {
		nombre: "",
		telefono: "",
		correo: "",
		mensaje: {
			text: "",
			maxlength: 255
		},
		submitted: false
    };
  },
  methods: {
    // submit form handler
    submit: function() {
	  this.submitted = true;
	  this.sendRequest()
      .then(r => {
        //console.log(r + "parece que funciono.");
      })
	},
	async sendRequest () {
		const response = await fetch('mail.php', {
			method: 'POST',
			headers: {
				'content-type': 'application/json'
			},
			body: JSON.stringify({
				nombre: this.nombre,
				correo: this.correo,
				telefono: this.telefono,
				mensaje: this.mensaje.text
				})
		})
		return response.json();
	}
  }
};
</script>
