import Vue from "vue";
import Router from "vue-router";
import AppHeader from "./layout/AppHeader";
import AppFooter from "./layout/AppFooter";
import Inicio from "./views/Inicio.vue";
import QuienesSomos from "./views/QuienesSomos.vue";
import Contacto from "./views/Contacto.vue";
import Multinivel from "./views/Multinivel.vue";

Vue.use(Router);

export default new Router({
    linkExactActiveClass: "active",
    routes: [{
            path: "/",
            name: "inicio",
            components: {
                header: AppHeader,
                default: Inicio,
                footer: AppFooter
            }
        },
        {
            path: "/quienes-somos",
            name: "quienes-somos",
            components: {
                header: AppHeader,
                default: QuienesSomos,
                footer: AppFooter
            }
        },
        {
            path: "/contacto",
            name: "contacto",
            components: {
                header: AppHeader,
                default: Contacto,
                footer: AppFooter
            }
        },
        {
            path: "/multinivel",
            name: "mutinivel",
            components: {
                header: AppHeader,
                default: Multinivel,
                footer: AppFooter
            }
        }
    ],
    scrollBehavior: to => {
        if (to.hash) {
            return { selector: to.hash };
        } else {
            return { x: 0, y: 0 };
        }
    }
});